sql:
SELECT COUNT(candidate_id) AS total_candidates
FROM candidates
WHERE party = 'Democratic Party';

SELECT candidate_name
FROM candidates
WHERE candidate_id = 1;

SELECT AVG(result_percentage) AS average_win_percentage
FROM race_results
WHERE winner = 1;

SELECT SUM(vote_count) AS total_votes
FROM race_results
WHERE race_id = 1;

external_knowledge:
- The party 'Republican' often aligns with conservative political views in the United States;
- In this metaphor, 'beacon of the conservative light' symbolizes the Republican party;
- 'Sailors in its fleet' metaphorically refers to the candidates running for the party.

sql:
SELECT candidates.candidate_name, races.race_date
FROM candidates
JOIN races ON candidates.race_id = races.race_id;
